INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('heelevel3-d0d1b9a2-moex-00485', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-110-0e802df0', 'sub-heelevel3-d0d1b9a2-05', NULL, 'single_choice', '查核人員執行查核工作，應持續評估所獲得之證據，是否存有舞弊之跡象。當查核人員察覺 舞弊的存在時，下列敘述何者錯誤？', '["若導因於該舞弊之不實表達可能非屬重大，可以不必與管理階層討論，但須將察覺舞弊情 況記載於工作底稿中", "查核人員如果察覺高階管理階層可能參與舞弊，應直接告知治理單位", "查核人員不應該對管理階層及治理單位以外之人員，揭露舞弊發生的可能性", "若舞弊的情況存在重大不實表達風險，查核人員應考量管理階層及治理單位對調查潛在舞 弊風險，以及執行因應措施的誠信、能力與合作程度，以評估是否繼續接受查核委任"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:02+00:00", "source_pdf_sha1": "64ede6b2988b", "answer_pdf_sha1": "770329449bc6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "326", "s": "1107", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00486', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-110-0e802df0', 'sub-heelevel3-d0d1b9a2-05', NULL, 'single_choice', '我國審計準則有關查核人員對所評估風險之因應，下列敘述何者正確？', '["查核人員判斷某一個別項目聲明之重大不實表達風險係屬顯著風險時，不必執行因應此風 險之證實程序", "當對某一顯著風險之因應方式僅為證實程序時，該等程序至少應包括證實分析性程序", "查核人員所評估之重大不實表達風險不論為何，均應對每一重大交易類別、科目餘額及揭 露事項，設計及執行證實程序", "查核人員如於期中執行證實程序，應對剩餘期間執行控制測試即可，以提供延伸期中查核 結論至期末之合理基礎"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:02+00:00", "source_pdf_sha1": "64ede6b2988b", "answer_pdf_sha1": "770329449bc6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "326", "s": "1107", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00487', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-110-0e802df0', 'sub-heelevel3-d0d1b9a2-05', NULL, 'single_choice', '下列何者最能描述規劃階段所執行分析性程序之目的？', '["決定委任合約應執行之事項", "辨識異常狀況以投入更多查核", "決定客戶之財務報表何項聲明最重要", "決定查核時間、性質與範圍"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:02+00:00", "source_pdf_sha1": "64ede6b2988b", "answer_pdf_sha1": "770329449bc6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "326", "s": "1107", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00488', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-110-0e802df0', 'sub-heelevel3-d0d1b9a2-05', NULL, 'single_choice', '會計師於了解甲公司之內部控制時，發現其職能分工不適當，此情況顯示該公司下列內部控 制組成要素中何者可能存有顯著缺失？', '["控制環境", "風險評估流程", "控制作業", "控制之監督"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:02+00:00", "source_pdf_sha1": "64ede6b2988b", "answer_pdf_sha1": "770329449bc6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "326", "s": "1107", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00489', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-110-0e802df0', 'sub-heelevel3-d0d1b9a2-05', NULL, 'single_choice', '審計準則公報第51號「查核規劃及執行之重大性」 ，對於查核人員執行重大性之應用，下 列敘述何者錯誤？', '["判斷重大性水準時，查核人員應先決定整體財務報表重大性，亦得進一步分配初步判斷重 大性水準至財務報表的各科目", "查核人員於執行查核過程中，如發現特定重大交易導致必須修正財務報表重大性時，除了 修訂該特定交易之重大性外，亦應考量修正財務報表整體重大性", "查核人員於決定執行重大性時，不能僅就當年度之財務報表要素進行評估，以往年度查核 所辨認不實表達之性質與範圍，也會影響當年度執行重大性之決定", "查核人員於總各科目不實表達後，發現不實表達超過財務報表整體重大性，係因某特定 科目估計不實表達遠超過該科目執行重大性所致，查核人員得修正財務報表整體重大性"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:02+00:00", "source_pdf_sha1": "64ede6b2988b", "answer_pdf_sha1": "770329449bc6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "326", "s": "1107", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00490', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-110-0e802df0', 'sub-heelevel3-d0d1b9a2-05', NULL, 'single_choice', '集團主辦會計師決定為集團財務報表組成個體（子公司）其他查核人員之工作承擔責任時， 下列敘述何者錯誤？', '["集團主辦會計師團隊必須參與組成個體查核人員之工作，工作深度需達到可對集團財務報 表表示意見之程度", "集團主辦會計師團隊必須為組成個體決定其查核重大性，且組成個體重大性應低於集團財 務報表整體重大性", "集團主辦會計師應取得組成個體查核會計師出具之聲明書及查核報告，並將該查核報告與 集團查核報告一併列報", "集團主辦會計師團隊應決定並評估組成個體查核人員之工作是否足夠、是否需複核組成個 體查核人員之工作底稿"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:02+00:00", "source_pdf_sha1": "64ede6b2988b", "answer_pdf_sha1": "770329449bc6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "326", "s": "1107", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00491', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-110-0e802df0', 'sub-heelevel3-d0d1b9a2-05', NULL, 'single_choice', 'A會計師受託查核甲公司X1年度（X1年1月1日至12月31日）財務報表，於X2年3月 1日結束外勤工作，返回事務所。在撰寫查核報告期間，甲公司之客戶於X2年3月8日發生 倒閉，導致該應收帳款無法收回。A會計師因此重新評估甲公司X1年12月31日之應收帳 款備抵呆帳是否提列足額，並於X2年3月20日完成查核程序，3月25日完成查核報告草 稿，3月31日甲公司財務報表經董事會通過。查核報告日最可能為那一天？', '["X2年3月1日", "X2年3月2日", "X2年3月20日", "X2年3月31日"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:02+00:00", "source_pdf_sha1": "64ede6b2988b", "answer_pdf_sha1": "770329449bc6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "326", "s": "1107", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00492', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-110-0e802df0', 'sub-heelevel3-d0d1b9a2-05', NULL, 'single_choice', '下列那一項查核程式可能屬於控制測試？', '["核對應收帳款總帳與明細帳餘額的一致性", "函證應收帳餘額", "評估應收帳款備抵呆帳的合理性", "檢查應收帳款入帳與出貨時點的一致性"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:02+00:00", "source_pdf_sha1": "64ede6b2988b", "answer_pdf_sha1": "770329449bc6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "326", "s": "1107", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00493', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-110-0e802df0', 'sub-heelevel3-d0d1b9a2-05', NULL, 'single_choice', '有關工作底稿之敘述，下列何者錯誤？', '["工作底稿之保管年限，自查核報告日起算不短於5年", "非經客戶同意，皆不得將工作底稿內容洩露給任何第三者", "若事務所內部契約無約定，會計師之工作底稿所有權屬於會計師事務所所有", "工作底稿保管期限屆滿前，不得予以刪除或銷毀"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:02+00:00", "source_pdf_sha1": "64ede6b2988b", "answer_pdf_sha1": "770329449bc6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "326", "s": "1107", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00494', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-110-0e802df0', 'sub-heelevel3-d0d1b9a2-05', NULL, 'single_choice', '查核人員原預估控制風險水準是10%，經執行內部控制測試後評估控制風險水準為25%，則 查核人員最好應：', '["提高可接受查核風險水準", "降低可接受查核風險水準", "降低固有風險水準", "降低可接受偵查風險水準"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:02+00:00", "source_pdf_sha1": "64ede6b2988b", "answer_pdf_sha1": "770329449bc6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "326", "s": "1107", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL)
